@charset "UTF-8";
.section-container {
  height: 100%;
  padding: 20px 10px 10px;
}

.title-container {
  position: relative;
  text-align: left;
  margin-bottom: 12px;
}

.line-container {
  position: relative;
  display: inline-block;
}

.background-bar {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, 10%);
  width: 100%;
  height: 0.8em;
  background-color: #E1F9B7;
  z-index: 0;
  border-radius: 4px;
}

.styled-title {
  font-family: "Poppins", sans-serif;
  font-size: 22px;
  font-weight: bold;
  color: #2C3034;
  position: relative;
  z-index: 1;
  margin: 0;
}

.section-description {
  font-family: "Poppins", sans-serif;
  font-size: 16px;
  color: #596D7B;
  text-align: left;
  margin-bottom: 40px;
}

.advantages-container {
  display: flex;
  flex-direction: row;
  justify-content: space-between;
  gap: 20px;
}

@media (max-width: 768px) {
  .advantages-container {
    flex-direction: column;
  }
}
/* BOXES */
.advantage-box {
  flex: 1;
  border: 1px solid #E6E9F2;
  border-radius: 8px;
  padding: 20px;
  text-align: left;
  box-shadow: 0px 4px 10px rgba(0, 0, 0, 0.05);
  background-color: #FFFFFF;
  position: relative;
  transition: background-color 0.5s ease;
}

.advantage-box:hover {
  background-color: #F5FFF4;
}

/* Étape 1 : vert clair */
.advantage-box-green {
  background-color: #ECFCE5;
  border: 1px solid #ECFCE5;
}

/* Étape 2 : le style initial (par exemple bordure bleue) */
.advantage-box-blue {
  border: 2px solid #2E6EE5;
}

/* Étape 3 : bordure grise classique */
.advantage-box-grey {
  /* Valeurs par défaut */
  /* border: 1px solid #E6E9F2; */
}

/* TITRES D'ÉTAPE */
.step-title {
  font-family: "Poppins", sans-serif;
  font-size: 16px;
  font-weight: bold;
  color: #2C3034;
  margin-bottom: 4px;
}

.step-subtitle {
  font-family: "Poppins", sans-serif;
  font-size: 18px;
  font-weight: bold;
  color: #2C3034;
  margin: 0 0 16px 0;
}

/* On crée une classe supplémentaire pour colorer uniquement
   le texte "Étape 2" et "Étape 3" en bleu */
.step-title-blue {
  color: #2E6EE5;
}

/* TEXTE */
.advantage-text {
  font-family: "Poppins", sans-serif;
  font-size: 16px;
  color: #596D7B;
}

.icon-container {
  position: absolute;
  top: 20px;
  right: 20px;
  width: 24px;
  height: 24px;
}

